      for (j in 1:M) {
        real s = 0;
        for (d in 1:D) {
          real t = (X[i, d] - X_new[j, d]) / rho[d];
          s += t * t;
        }
        Kx[i, j] = square(alpha) * exp(-0.5 * s);
      }
    }
    return Kx;
  }
}

data {
  int<lower=1> N;
  int<lower=1> D;
  matrix[N, D] X;
  int<lower=1> P;
  matrix[N, P] H;
  vector[N] y;
